     1→import React, { useMemo, useState } from 'react';
     2→import { Widget } from '../components/Widget';
     3→import { Modal } from '../components/Modal';
     4→import { RecurringEventDialog } from '../components/RecurringEventDialog';
     5→import { DayView } from '../components/DayView';
     6→import { WeekView } from '../components/WeekView';
     7→import { AgendaView } from '../components/AgendaView';
     8→import { useCalendarStore } from '../stores/useCalendarStore';
     9→import { useKanbanStore } from '../stores/useKanbanStore';
    10→import { REMINDER_OPTIONS } from '../services/eventReminders';
    11→import {
    12→  getStandardDateKey,
    13→  getFirstDayOfMonth,
    14→  getDaysInMonth,
    15→  getDaysInPrevMonth,
    16→  isToday,
    17→  isDateBetween,
    18→} from '../utils/dateUtils';
    19→import type { Task, CalendarEvent } from '../types';
    20→import { format, startOfMonth, endOfMonth, startOfWeek, endOfWeek, addDays } from 'date-fns';
    21→import { generateRecurringInstances, expandMultiDayEvent } from '../utils/recurrence';
    22→
    23→/**
    24→ * Calendar Widget - React Version
    25→ * Features:
    26→ * - Monthly/Weekly view toggle
    27→ * - Event management
    28→ * - Task date range bars (synced with Kanban)
    29→ * - Fully typed and tested
    30→ */
    31→export const Calendar: React.FC = () => {
    32→  const {
    33→    currentDate,
    34→    viewMode,
    35→    events,
    36→    setViewMode,
    37→    nextPeriod,
    38→    prevPeriod,
    39→    addEvent,
    40→    updateEvent,
    41→    deleteEvent,
    42→    createEventException,
    43→    updateRecurringSeries,
    44→    deleteRecurringSeries,
    45→  } = useCalendarStore();
    46→
    47→  const { tasks } = useKanbanStore();
    48→
    49→  // Expand recurring and multi-day events for current view
    50→  const expandedEvents = useMemo(() => {
    51→    const result: Record<string, CalendarEvent[]> = {};
    52→
    53→    // Determine view date range
    54→    let viewStart: Date;
    55→    let viewEnd: Date;
    56→
    57→    if (viewMode === 'monthly') {
    58→      viewStart = startOfMonth(currentDate);
    59→      viewEnd = endOfMonth(currentDate);
    60→    } else if (viewMode === 'weekly') {
    61→      viewStart = startOfWeek(currentDate);
    62→      viewEnd = endOfWeek(currentDate);
    63→    } else {
    64→      // Daily view
    65→      viewStart = currentDate;
    66→      viewEnd = addDays(currentDate, 1);
    67→    }
    68→
    69→    // Process all events
    70→    Object.entries(events).forEach(([dateKey, dayEvents]) => {
    71→      dayEvents.forEach((event) => {
    72→        if (event.recurrence) {
    73→          // Generate recurring instances
    74→          const instances = generateRecurringInstances(event, dateKey, viewStart, viewEnd);
    75→          instances.forEach(({ date, event: instanceEvent }) => {
    76→            // Also expand multi-day for each recurring instance
    77→            const multiDayInstances = expandMultiDayEvent(instanceEvent, date);
    78→            multiDayInstances.forEach((multiDayEvent, multiDayDate) => {
    79→              if (!result[multiDayDate]) result[multiDayDate] = [];
    80→              result[multiDayDate].push(multiDayEvent);
    81→            });
    82→          });
    83→        } else {
    84→          // Non-recurring event - check if multi-day
    85→          const multiDayInstances = expandMultiDayEvent(event, dateKey);
    86→          multiDayInstances.forEach((multiDayEvent, multiDayDate) => {
    87→            if (!result[multiDayDate]) result[multiDayDate] = [];
    88→            result[multiDayDate].push(multiDayEvent);
    89→          });
    90→        }
    91→      });
    92→    });
    93→
    94→    return result;
    95→  }, [events, currentDate, viewMode]);
    96→
    97→  // Modal state
    98→  const [isModalOpen, setIsModalOpen] = useState(false);
    99→  const [selectedDateKey, setSelectedDateKey] = useState('');
   100→  const [newEventTitle, setNewEventTitle] = useState('');
   101→  const [newEventDescription, setNewEventDescription] = useState('');
   102→  const [editingEventId, setEditingEventId] = useState<string | null>(null);
   103→  const [isAllDay, setIsAllDay] = useState(true);
   104→  const [startTime, setStartTime] = useState('09:00');
   105→  const [endTime, setEndTime] = useState('10:00');
   106→  const [eventEndDate, setEventEndDate] = useState<string>(''); // Multi-day end date
   107→  const [recurrenceType, setRecurrenceType] = useState<'none' | 'daily' | 'weekly' | 'monthly'>('none');
   108→
   109→  // Recurrence options state
   110→  const [weeklyDays, setWeeklyDays] = useState<number[]>([]);
   111→  const [monthlyDay, setMonthlyDay] = useState<number>(1);
   112→  const [recurrenceEndType, setRecurrenceEndType] = useState<'never' | 'after' | 'until'>('never');
   113→  const [recurrenceEndCount, setRecurrenceEndCount] = useState<number>(10);
   114→  const [recurrenceEndDate, setRecurrenceEndDate] = useState<string>('');
   115→
   116→  // Reminder state
   117→  const [eventReminders, setEventReminders] = useState<number[]>([]);
   118→
   119→  // Location state
   120→  const [eventLocation, setEventLocation] = useState<string>('');
   121→
   122→  // Recurring event dialog state
   123→  const [isRecurringDialogOpen, setIsRecurringDialogOpen] = useState(false);
   124→  const [recurringAction, setRecurringAction] = useState<'edit' | 'delete'>('edit');
   125→  const [pendingRecurringEvent, setPendingRecurringEvent] = useState<CalendarEvent | null>(null);
   126→
   127→  const handleDayClick = (dateKey: string) => {
   128→    setSelectedDateKey(dateKey);
   129→    setNewEventTitle('');
   130→    setNewEventDescription('');
   131→    setEditingEventId(null);
   132→    setIsAllDay(true);
   133→    setStartTime('09:00');
   134→    setEndTime('10:00');
   135→    setIsModalOpen(true);
   136→  };
   137→
   138→  const handleAddEvent = () => {
   139→    if (newEventTitle.trim()) {
   140→      const eventData: Partial<CalendarEvent> = {
   141→        title: newEventTitle.trim(),
   142→        description: newEventDescription.trim(),
   143→        isAllDay,
   144→        startTime: !isAllDay ? startTime : undefined,
   145→        endTime: !isAllDay ? endTime : undefined,
   146→        endDate: eventEndDate || undefined, // Multi-day end date
   147→        reminders: eventReminders.length > 0 ? eventReminders : undefined,
   148→        location: eventLocation.trim() || undefined,
   149→      };
   150→
   151→      // Add recurrence if selected (only for new events)
   152→      if (recurrenceType !== 'none' && !editingEventId) {
   153→        eventData.recurrence = {
   154→          frequency: recurrenceType,
   155→          interval: 1,
   156→          endType: recurrenceEndType,
   157→          endCount: recurrenceEndType === 'after' ? recurrenceEndCount : undefined,
   158→          endDate: recurrenceEndType === 'until' ? recurrenceEndDate : undefined,
   159→        };
   160→
   161→        // Add weekly-specific options
   162→        if (recurrenceType === 'weekly' && weeklyDays.length > 0) {
   163→          eventData.recurrence.daysOfWeek = weeklyDays;
   164→        }
   165→
   166→        // Add monthly-specific options
   167→        if (recurrenceType === 'monthly') {
   168→          eventData.recurrence.dayOfMonth = monthlyDay;
   169→        }
   170→      }
   171→
   172→      if (editingEventId) {
   173→        // Check if editing an exception (this event only) or series (all events)
   174→        if (editingEventId.includes('-exception')) {
   175→          // Create exception for this event only
   176→          const parentId = editingEventId.replace('-exception', '');
   177→          createEventException(selectedDateKey, parentId, eventData);
   178→        } else {
   179→          // Check if this is a recurring series
   180→          const event = dayEvents.find((e) => e.id === editingEventId);
   181→          if (event?.recurrence) {
   182→            // Update entire recurring series
   183→            updateRecurringSeries(editingEventId, eventData);
   184→          } else {
   185→            // Update single event
   186→            updateEvent(selectedDateKey, editingEventId, eventData.title!, eventData.description, eventData);
   187→          }
   188→        }
   189→        setEditingEventId(null);
   190→      } else {
   191→        // Add new event
   192→        addEvent(selectedDateKey, eventData.title!, eventData.description, eventData);
   193→      }
   194→      setNewEventTitle('');
   195→      setNewEventDescription('');
   196→      setIsAllDay(true);
   197→      setStartTime('09:00');
   198→      setEndTime('10:00');
   199→      setEventEndDate('');
   200→      setRecurrenceType('none');
   201→      setWeeklyDays([]);
   202→      setMonthlyDay(1);
   203→      setRecurrenceEndType('never');
   204→      setRecurrenceEndCount(10);
   205→      setRecurrenceEndDate('');
   206→      setEventReminders([]);
   207→      setEventLocation('');
   208→    }
   209→  };
   210→
   211→  const handleEditEvent = (event: CalendarEvent) => {
   212→    // Check if this is a recurring event or instance
   213→    const isRecurring = !!event.recurrence || !!event.recurrenceId;
   214→
   215→    if (isRecurring) {
   216→      // Show dialog to choose: edit this event or all events
   217→      setPendingRecurringEvent(event);
   218→      setRecurringAction('edit');
   219→      setIsRecurringDialogOpen(true);
   220→    } else {
   221→      // Non-recurring event - edit directly
   222→      setNewEventTitle(event.title);
   223→      setNewEventDescription(event.description || '');
   224→      setIsAllDay(event.isAllDay !== false);
   225→      setStartTime(event.startTime || '09:00');
   226→      setEndTime(event.endTime || '10:00');
   227→      setEventReminders(event.reminders || []);
   228→      setEventLocation(event.location || '');
   229→      setEditingEventId(event.id);
   230→    }
   231→  };
   232→
   233→  const handleCancelEdit = () => {
   234→    setNewEventTitle('');
   235→    setNewEventDescription('');
   236→    setIsAllDay(true);
   237→    setStartTime('09:00');
   238→    setEndTime('10:00');
   239→    setEventReminders([]);
   240→    setEventLocation('');
   241→    setEditingEventId(null);
   242→  };
   243→
   244→  const handleDeleteEvent = (eventId: string) => {
   245→    // Find the event to check if it's recurring
   246→    const event = dayEvents.find((e) => e.id === eventId);
   247→    if (!event) return;
   248→
   249→    const isRecurring = !!event.recurrence || !!event.recurrenceId;
   250→
   251→    if (isRecurring) {
   252→      // Show dialog to choose: delete this event or all events
   253→      setPendingRecurringEvent(event);
   254→      setRecurringAction('delete');
   255→      setIsRecurringDialogOpen(true);
   256→    } else {
   257→      // Non-recurring event - delete directly
   258→      deleteEvent(selectedDateKey, eventId);
   259→      if (editingEventId === eventId) {
   260→        handleCancelEdit();
   261→      }
   262→    }
   263→  };
   264→
   265→  // Handle editing this event only (create exception)
   266→  const handleEditThisEvent = () => {
   267→    if (!pendingRecurringEvent) return;
   268→
   269→    const parentId = pendingRecurringEvent.recurrenceId || pendingRecurringEvent.id;
   270→
   271→    // Pre-fill form with event data
   272→    setNewEventTitle(pendingRecurringEvent.title);
   273→    setNewEventDescription(pendingRecurringEvent.description || '');
   274→    setIsAllDay(pendingRecurringEvent.isAllDay !== false);
   275→    setStartTime(pendingRecurringEvent.startTime || '09:00');
   276→    setEndTime(pendingRecurringEvent.endTime || '10:00');
   277→    setEditingEventId(`${parentId}-exception`);
   278→
   279→    setPendingRecurringEvent(null);
   280→  };
   281→
   282→  // Handle editing all events in series
   283→  const handleEditAllEvents = () => {
   284→    if (!pendingRecurringEvent) return;
   285→
   286→    const parentId = pendingRecurringEvent.recurrenceId || pendingRecurringEvent.id;
   287→
   288→    // Pre-fill form with event data
   289→    setNewEventTitle(pendingRecurringEvent.title);
   290→    setNewEventDescription(pendingRecurringEvent.description || '');
   291→    setIsAllDay(pendingRecurringEvent.isAllDay !== false);
   292→    setStartTime(pendingRecurringEvent.startTime || '09:00');
   293→    setEndTime(pendingRecurringEvent.endTime || '10:00');
   294→    setEditingEventId(parentId);
   295→
   296→    setPendingRecurringEvent(null);
   297→  };
   298→
   299→  // Handle deleting this event only (create exception)
   300→  const handleDeleteThisEvent = () => {
   301→    if (!pendingRecurringEvent) return;
   302→
   303→    const parentId = pendingRecurringEvent.recurrenceId || pendingRecurringEvent.id;
   304→
   305→    // Create exception that marks this instance as deleted
   306→    createEventException(selectedDateKey, parentId, {
   307→      title: pendingRecurringEvent.title,
   308→      description: pendingRecurringEvent.description,
   309→      recurrenceException: true,
   310→      isAllDay: true, // Hidden exception
   311→    });
   312→
   313→    setPendingRecurringEvent(null);
   314→  };
   315→
   316→  // Handle deleting all events in series
   317→  const handleDeleteAllEvents = () => {
   318→    if (!pendingRecurringEvent) return;
   319→
   320→    const parentId = pendingRecurringEvent.recurrenceId || pendingRecurringEvent.id;
   321→    deleteRecurringSeries(parentId);
   322→
   323→    if (editingEventId === parentId || editingEventId?.startsWith(`${parentId}-`)) {
   324→      handleCancelEdit();
   325→    }
   326→
   327→    setPendingRecurringEvent(null);
   328→  };
   329→
   330→  const dayEvents = expandedEvents[selectedDateKey] || [];
   331→
   332→  return (
   333→    <Widget id="calendar" title="Calendar" category="Planning" draggable={false}>
   334→      <div className="calendar-widget h-full flex flex-col">
   335→        {/* Calendar Navigation - FROZEN */}
   336→        <div className="flex-shrink-0 px-4 pt-4">
   337→          <div className="calendar-nav flex items-center justify-between mb-4">
   338→          <button
   339→            onClick={prevPeriod}
   340→            className="px-3 py-1 bg-accent-blue hover:bg-accent-blue-hover text-white rounded transition-colors"
   341→          >
   342→            ← Prev
   343→          </button>
   344→
   345→          <div className="calendar-current-month text-center font-semibold text-text-light-primary dark:text-text-dark-primary">
   346→            {currentDate.toLocaleDateString('en-US', {
   347→              month: 'long',
   348→              year: 'numeric',
   349→            })}
   350→          </div>
   351→
   352→          <div className="flex gap-2">
   353→            {/* View Mode Switcher */}
   354→            <div className="flex gap-1 bg-surface-light-elevated dark:bg-surface-dark-elevated rounded p-1">
   355→              <button
   356→                onClick={() => setViewMode('monthly')}
   357→                className={`px-3 py-1 rounded text-sm transition-colors ${
   358→                  viewMode === 'monthly'
   359→                    ? 'bg-accent-blue text-white'
   360→                    : 'text-text-light-secondary dark:text-text-dark-secondary hover:bg-surface-light dark:hover:bg-surface-dark'
   361→                }`}
   362→              >
   363→                Month
   364→              </button>
   365→              <button
   366→                onClick={() => setViewMode('weekly')}
   367→                className={`px-3 py-1 rounded text-sm transition-colors ${
   368→                  viewMode === 'weekly'
   369→                    ? 'bg-accent-blue text-white'
   370→                    : 'text-text-light-secondary dark:text-text-dark-secondary hover:bg-surface-light dark:hover:bg-surface-dark'
   371→                }`}
   372→              >
   373→                Week
   374→              </button>
   375→              <button
   376→                onClick={() => setViewMode('daily')}
   377→                className={`px-3 py-1 rounded text-sm transition-colors ${
   378→                  viewMode === 'daily'
   379→                    ? 'bg-accent-blue text-white'
   380→                    : 'text-text-light-secondary dark:text-text-dark-secondary hover:bg-surface-light dark:hover:bg-surface-dark'
   381→                }`}
   382→              >
   383→                Day
   384→              </button>
   385→              <button
   386→                onClick={() => setViewMode('agenda')}
   387→                className={`px-3 py-1 rounded text-sm transition-colors ${
   388→                  viewMode === 'agenda'
   389→                    ? 'bg-accent-blue text-white'
   390→                    : 'text-text-light-secondary dark:text-text-dark-secondary hover:bg-surface-light dark:hover:bg-surface-dark'
   391→                }`}
   392→              >
   393→                List
   394→              </button>
   395→            </div>
   396→
   397→            {/* Print Button */}
   398→            <button
   399→              onClick={() => window.print()}
   400→              className="p-2 hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated rounded transition-colors no-print"
   401→              title="Print calendar"
   402→            >
   403→              🖨️
   404→            </button>
   405→
   406→            <button
   407→              onClick={nextPeriod}
   408→              className="px-3 py-1 bg-accent-blue hover:bg-accent-blue-hover text-white rounded transition-colors"
   409→            >
   410→              Next →
   411→            </button>
   412→          </div>
   413→        </div>
   414→      </div>
   415→
   416→      {/* Calendar Grid - SCROLLABLE */}
   417→      <div className="flex-1 overflow-y-auto px-4 pb-4">
   418→          {viewMode === 'monthly' ? (
   419→            <MonthView
   420→              currentDate={currentDate}
   421→              events={expandedEvents}
   422→              tasks={tasks}
   423→              onDayClick={handleDayClick}
   424→            />
   425→          ) : viewMode === 'weekly' ? (
   426→            <WeekView
   427→              currentDate={currentDate}
   428→              events={expandedEvents}
   429→              tasks={tasks}
   430→              onDayClick={handleDayClick}
   431→              onEventClick={(event, dateKey) => {
   432→                setSelectedDateKey(dateKey);
   433→                setNewEventTitle(event.title);
   434→                setNewEventDescription(event.description || '');
   435→                setIsAllDay(event.isAllDay !== false);
   436→                setStartTime(event.startTime || '09:00');
   437→                setEndTime(event.endTime || '10:00');
   438→                setEditingEventId(event.id);
   439→                setIsModalOpen(true);
   440→              }}
   441→              showTimeSlots={true}
   442→            />
   443→          ) : viewMode === 'daily' ? (
   444→            <DayView
   445→              date={currentDate}
   446→              events={expandedEvents[format(currentDate, 'yyyy-MM-dd')] || []}
   447→              onEventClick={(event, dateKey) => {
   448→                setSelectedDateKey(dateKey);
   449→                setNewEventTitle(event.title);
   450→                setNewEventDescription(event.description || '');
   451→                setIsAllDay(event.isAllDay !== false);
   452→                setStartTime(event.startTime || '09:00');
   453→                setEndTime(event.endTime || '10:00');
   454→                setEditingEventId(event.id);
   455→                setIsModalOpen(true);
   456→              }}
   457→              onTimeSlotClick={(hour) => {
   458→                const dateKey = format(currentDate, 'yyyy-MM-dd');
   459→                setSelectedDateKey(dateKey);
   460→                setNewEventTitle('');
   461→                setNewEventDescription('');
   462→                setEditingEventId(null);
   463→                setIsAllDay(false);
   464→                setStartTime(`${hour.toString().padStart(2, '0')}:00`);
   465→                setEndTime(`${(hour + 1).toString().padStart(2, '0')}:00`);
   466→                setIsModalOpen(true);
   467→              }}
   468→            />
   469→          ) : (
   470→            <AgendaView
   471→              events={expandedEvents}
   472→              currentDate={currentDate}
   473→              daysToShow={14}
   474→              onEventClick={(event, dateKey) => {
   475→                setSelectedDateKey(dateKey);
   476→                setNewEventTitle(event.title);
   477→                setNewEventDescription(event.description || '');
   478→                setIsAllDay(event.isAllDay !== false);
   479→                setStartTime(event.startTime || '09:00');
   480→                setEndTime(event.endTime || '10:00');
   481→                setEventReminders(event.reminders || []);
   482→                setEditingEventId(event.id);
   483→                setIsModalOpen(true);
   484→              }}
   485→            />
   486→          )}
   487→        </div>
   488→      </div>
   489→
   490→      {/* Event Modal */}
   491→      <Modal
   492→        isOpen={isModalOpen}
   493→        onClose={() => setIsModalOpen(false)}
   494→        title={`Events for ${selectedDateKey}`}
   495→      >
   496→        <div className="space-y-4">
   497→          {/* Existing Events List */}
   498→          {dayEvents.length > 0 && (
   499→            <div className="space-y-2">
   500→              <h4 className="text-sm font-medium text-text-light-secondary dark:text-text-dark-secondary">
   501→                Events ({dayEvents.length})
   502→              </h4>
   503→              {dayEvents.map((event) => (
   504→                <div
   505→                  key={event.id}
   506→                  className={`p-3 rounded-lg transition-all ${
   507→                    editingEventId === event.id
   508→                      ? 'bg-accent-blue/10 dark:bg-accent-blue/20 ring-2 ring-accent-blue'
   509→                      : 'bg-surface-light-elevated dark:bg-surface-dark-elevated'
   510→                  }`}
   511→                >
   512→                  <div className="flex items-start justify-between gap-2">
   513→                    <div className="flex-1 min-w-0">
   514→                      <div className="font-medium text-text-light-primary dark:text-text-dark-primary">{event.title}</div>
   515→                      {event.startTime && (
   516→                        <div className="text-sm text-accent-blue dark:text-accent-blue-hover mt-1">
   517→                          {event.startTime} {event.endTime && `- ${event.endTime}`}
   518→                        </div>
   519→                      )}
   520→                      {event.description && (
   521→                        <div className="text-sm text-text-light-secondary dark:text-text-dark-secondary mt-1">
   522→                          {event.description}
   523→                        </div>
   524→                      )}
   525→                    </div>
   526→                    <div className="flex gap-2">
   527→                      <button
   528→                        onClick={() => handleEditEvent(event)}
   529→                        className="px-3 py-1 text-sm bg-accent-blue text-white rounded hover:bg-accent-blue-hover transition-colors"
   530→                      >
   531→                        Edit
   532→                      </button>
   533→                      <button
   534→                        onClick={() => handleDeleteEvent(event.id)}
   535→                        className="px-3 py-1 text-sm bg-status-error text-white rounded hover:opacity-80 transition-opacity"
   536→                      >
   537→                        Delete
   538→                      </button>
   539→                    </div>
   540→                  </div>
   541→                </div>
   542→              ))}
   543→            </div>
   544→          )}
   545→
   546→          {/* Add/Edit Event Form */}
   547→          <div>
   548→            <label
   549→              htmlFor="new-event-input"
   550→              className="block text-sm font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2"
   551→            >
   552→              {editingEventId ? 'Edit Event' : 'Add New Event'}
   553→            </label>
   554→            <div className="space-y-2">
   555→              <input
   556→                id="new-event-input"
   557→                type="text"
   558→                value={newEventTitle}
   559→                onChange={(e) => setNewEventTitle(e.target.value)}
   560→                placeholder="Enter event title..."
