   850→// ==================== MONTH VIEW COMPONENT ====================
   851→
   852→interface MonthViewProps {
   853→  currentDate: Date;
   854→  events: Record<string, CalendarEvent[]>;
   855→  tasks: Task[];
   856→  onDayClick: (dateKey: string) => void;
   857→}
   858→
   859→const MonthView: React.FC<MonthViewProps> = ({
   860→  currentDate,
   861→  events,
   862→  tasks,
   863→  onDayClick,
   864→}) => {
   865→  const year = currentDate.getFullYear();
   866→  const month = currentDate.getMonth();
   867→
   868→  const firstDay = getFirstDayOfMonth(currentDate);
   869→  const daysInMonth = getDaysInMonth(currentDate);
   870→  const daysInPrevMonth = getDaysInPrevMonth(currentDate);
   871→
   872→  const days = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
   873→
   874→  // Generate day cells
   875→  const dayCells = useMemo(() => {
   876→    const cells = [];
   877→
   878→    // Previous month days
   879→    for (let i = firstDay - 1; i >= 0; i--) {
   880→      const dayNum = daysInPrevMonth - i;
   881→      const date = new Date(year, month - 1, dayNum);
   882→      cells.push({
   883→        date,
   884→        dayNum,
   885→        isOtherMonth: true,
   886→        isToday: false,
   887→        dateKey: getStandardDateKey(date),
   888→      });
   889→    }
   890→
   891→    // Current month days
   892→    for (let i = 1; i <= daysInMonth; i++) {
   893→      const date = new Date(year, month, i);
   894→      const dateKey = getStandardDateKey(date);
   895→      cells.push({
   896→        date,
   897→        dayNum: i,
   898→        isOtherMonth: false,
   899→        isToday: isToday(date),
   900→        dateKey,
   901→      });
   902→    }
   903→
   904→    // Next month days (to fill grid)
   905→    const totalCells = cells.length;
   906→    const remainingCells = 35 - totalCells;
   907→    for (let i = 1; i <= remainingCells; i++) {
   908→      const date = new Date(year, month + 1, i);
   909→      cells.push({
   910→        date,
   911→        dayNum: i,
   912→        isOtherMonth: true,
   913→        isToday: false,
   914→        dateKey: getStandardDateKey(date),
   915→      });
   916→    }
   917→
   918→    return cells;
   919→  }, [year, month, firstDay, daysInMonth, daysInPrevMonth]);
   920→
   921→  // Filter tasks with date ranges (memoized to avoid re-filtering on every render)
   922→  const tasksWithDates = useMemo(
   923→    () => tasks.filter((task) => task.startDate && task.dueDate),
   924→    [tasks]
   925→  );
   926→
   927→  return (
   928→    <div className="calendar-month-view flex-1 grid grid-rows-[auto_1fr] gap-2">
   929→      {/* Day headers */}
   930→      <div className="grid grid-cols-7 gap-px">
   931→        {days.map((day) => (
   932→          <div
   933→            key={day}
   934→            className="calendar-day-header text-center font-semibold text-sm text-text-light-secondary dark:text-text-dark-secondary py-2"
   935→          >
   936→            {day}
   937→          </div>
   938→        ))}
   939→      </div>
   940→
   941→      {/* Day cells */}
   942→      <div className="grid grid-cols-7 grid-rows-5 gap-px">
   943→        {dayCells.map((cell, index) => {
   944→          const hasEvent = (events[cell.dateKey]?.length || 0) > 0;
   945→
   946→          return (
   947→            <DayCell
   948→              key={index}
   949→              date={cell.date}
   950→              dayNum={cell.dayNum}
   951→              isOtherMonth={cell.isOtherMonth}
   952→              isToday={cell.isToday}
   953→              hasEvent={hasEvent}
   954→              dateKey={cell.dateKey}
   955→              tasks={tasksWithDates}
   956→              events={events}
   957→              onClick={() => !cell.isOtherMonth && onDayClick(cell.dateKey)}
   958→            />
   959→          );
   960→        })}
   961→      </div>
   962→    </div>
   963→  );
   964→};
   965→
   966→// ==================== DAY CELL COMPONENT ====================
   967→
   968→interface DayCellProps {
   969→  date: Date;
   970→  dayNum: number;
   971→  isOtherMonth: boolean;
   972→  isToday: boolean;
   973→  hasEvent: boolean;
   974→  dateKey: string;
   975→  tasks: Task[];
   976→  events: Record<string, CalendarEvent[]>;
   977→  onClick: () => void;
   978→}
   979→
   980→const DayCellComponent: React.FC<DayCellProps> = ({
   981→  date,
   982→  dayNum,
   983→  isOtherMonth,
   984→  isToday,
   985→  hasEvent,
   986→  dateKey,
   987→  tasks,
   988→  events,
   989→  onClick,
   990→}) => {
   991→  // Find tasks that overlap this day
   992→  const overlappingTasks = tasks.filter((task) => {
   993→    const startDate = new Date(task.startDate!);
   994→    const dueDate = new Date(task.dueDate!);
   995→    return isDateBetween(date, startDate, dueDate);
   996→  });
   997→
   998→  const priorityColors = {
   999→    low: 'bg-accent-cyan',
  1000→    medium: 'bg-status-warning',
  1001→    high: 'bg-status-error',
  1002→  };
  1003→
  1004→  return (
  1005→    <div
  1006→      onClick={onClick}
  1007→      className={`
  1008→        calendar-day
  1009→        relative
  1010→        border rounded
  1011→        p-2
  1012→        min-h-[100px]
  1013→        cursor-pointer
  1014→        transition-all
  1015→        hover:shadow-md
  1016→        ${isOtherMonth ? 'bg-neutral-100 dark:bg-neutral-700 opacity-50' : 'bg-surface-light-elevated dark:bg-neutral-800'}
  1017→        ${isToday ? 'ring-2 ring-accent-cyan' : 'border-neutral-200 dark:border-neutral-700'}
  1018→        ${hasEvent ? 'border-accent-magenta' : ''}
  1019→      `}
  1020→    >
  1021→      {/* Day number */}
  1022→      <div
  1023→        className={`
  1024→          calendar-day-number
  1025→          text-sm font-semibold
  1026→          ${isToday ? 'text-accent-cyan' : 'text-text-light-secondary dark:text-text-dark-secondary'}
  1027→        `}
  1028→      >
  1029→        {dayNum}
  1030→      </div>
  1031→
  1032→      {/* Event indicator dot */}
  1033→      {hasEvent && (
  1034→        <div className="absolute top-1 right-1 w-2 h-2 bg-accent-magenta rounded-full"></div>
  1035→      )}
  1036→
  1037→      {/* Event bars (multi-day events shown as colored bars) */}
  1038→      {hasEvent && (
  1039→        <div className="mt-1 space-y-1">
  1040→          {events[dateKey].slice(0, 2).map((event) => {
  1041→            const isMultiDay = event._isMultiDayPart;
  1042→            const isFirst = event._isMultiDayFirst;
  1043→            const isLast = event._isMultiDayLast;
  1044→
  1045→            return (
  1046→              <div
  1047→                key={event.id}
  1048→                className={`
  1049→                  text-xs
  1050→                  px-1
  1051→                  py-0.5
  1052→                  text-white
  1053→                  font-medium
  1054→                  truncate
  1055→                  bg-accent-magenta
  1056→                  ${isMultiDay ? (isFirst ? 'rounded-l' : isLast ? 'rounded-r' : '') : 'rounded'}
  1057→                `}
  1058→                title={event.title}
  1059→              >
  1060→                {event.title}
  1061→              </div>
  1062→            );
  1063→          })}
  1064→          {events[dateKey].length > 2 && (
  1065→            <div className="text-xs text-text-light-secondary dark:text-text-dark-secondary px-1">
  1066→              +{events[dateKey].length - 2} more
  1067→            </div>
  1068→          )}
  1069→        </div>
  1070→      )}
  1071→
  1072→      {/* Task bars */}
  1073→      <div className="mt-1 space-y-1">
  1074→        {overlappingTasks.slice(0, 2).map((task) => (
  1075→          <div
  1076→            key={task.id}
  1077→            className={`
  1078→              calendar-task-bar
  1079→              text-xs
  1080→              px-1
  1081→              py-0.5
  1082→              rounded
  1083→              text-white
  1084→              truncate
  1085→              ${priorityColors[task.priority || 'medium']}
  1086→            `}
  1087→            title={task.title}
  1088→          >
  1089→            {task.title}
  1090→          </div>
  1091→        ))}
  1092→        {overlappingTasks.length > 2 && (
  1093→          <div className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
  1094→            +{overlappingTasks.length - 2} more
  1095→          </div>
  1096→        )}
  1097→      </div>
  1098→    </div>
  1099→  );
  1100→};
  1101→
  1102→// Memoize DayCell to prevent unnecessary re-renders (35 cells per month view)
