     2→ * Week View Component
     3→ *
     4→ * Displays a 7-day week with time slots for each day
     5→ * Features: time slots (hourly), timed events, all-day events, task bars
     6→ */
     7→
     8→import React, { useMemo } from 'react';
     9→import type { CalendarEvent, Task } from '../types';
    10→import { getLegacyDateKey, isToday, isDateBetween } from '../utils/dateUtils';
    11→
    12→interface WeekViewProps {
    13→  currentDate: Date;
    14→  events: Record<string, CalendarEvent[]>;
    15→  tasks: Task[];
    16→  onDayClick: (dateKey: string) => void;
    17→  onEventClick?: (event: CalendarEvent, dateKey: string) => void;
    18→  showTimeSlots?: boolean;
    19→}
    20→
    21→export const WeekView: React.FC<WeekViewProps> = ({
    22→  currentDate,
    23→  events,
    24→  tasks,
    25→  onDayClick,
    26→  onEventClick,
    27→  showTimeSlots = true,
    28→}) => {
    29→  const days = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
    30→  const hours = showTimeSlots ? Array.from({ length: 24 }, (_, i) => i) : [];
    31→
    32→  // Get start of week (Sunday)
    33→  const startOfWeek = new Date(currentDate);
    34→  startOfWeek.setDate(startOfWeek.getDate() - startOfWeek.getDay());
    35→
    36→  const weekDays = useMemo(() => {
    37→    return Array.from({ length: 7 }, (_, i) => {
    38→      const day = new Date(startOfWeek);
    39→      day.setDate(day.getDate() + i);
    40→      return day;
    41→    });
    42→  }, [startOfWeek]);
    43→
    44→  const tasksWithDates = useMemo(() => {
    45→    return tasks.filter((task) => task.startDate && task.dueDate);
    46→  }, [tasks]);
    47→
    48→  // Parse time string "HH:MM" to decimal hours
    49→  const parseTime = (timeStr: string): number => {
    50→    const [hours, minutes] = timeStr.split(':').map(Number);
    51→    return hours + minutes / 60;
    52→  };
    53→
